mapper.select:
SELECT *
FROM app_message
WHERE conversation_id = #{conversationId}
  AND deleted_at IS NULL
ORDER BY id DESC
LIMIT #{limit}

SELECT *
FROM app_message
WHERE conversation_id = #{conversationId}
  AND deleted_at IS NULL
ORDER BY id ASC
LIMIT #{limit}

SELECT *
FROM (
    SELECT *
    FROM app_message
    WHERE conversation_id = #{conversationId}
      AND deleted_at IS NULL
    ORDER BY id DESC
    LIMIT #{limit}
) recent_rows
ORDER BY id ASC

SELECT *
FROM (
    SELECT *
    FROM app_message
    WHERE conversation_id = #{conversationId}
      AND deleted_at IS NULL
      AND id < #{beforeId}
    ORDER BY id DESC
    LIMIT #{limit}
) older_rows
ORDER BY id ASC

SELECT MAX(swipe_index)
FROM app_message
WHERE st_message_ref = #{stMessageRef}

